canvas.init:
function init(canvas, params) {
  var ctx = canvas.getContext('2d');
  var rows = params.rows || 15, cols = params.cols || 20;
  var speed = params.speed || 0.03;
  var amp = params.amplitude || 30;
  var color = getComputedStyle(canvas).getPropertyValue('--ct-text-strong').trim() || '#ffffff';
  var t = 0;
  function draw() {
    ctx.clearRect(0, 0, 300, 180);
    ctx.strokeStyle = color;
    ctx.globalAlpha = 0.2;
    ctx.lineWidth = 1;
    t -= speed;
    var pts = [];
    for (var y = 0; y < rows; y++) {
      pts[y] = [];
      for (var x = 0; x < cols; x++) {
        var px = x * 20 - 50;
        var py = y * 20;
        var pz = Math.sin(x * 0.4 + t) * Math.cos(y * 0.4 + t) * amp;
        var s = 300 / (300 + py);
        pts[y][x] = { x: 150 + (px - 150) * s, y: 40 + (py + pz) * s };
      }
    }
    for (var y2 = 0; y2 < rows - 1; y2++) {
      for (var x2 = 0; x2 < cols - 1; x2++) {
        ctx.beginPath();
        ctx.moveTo(pts[y2][x2].x, pts[y2][x2].y);
        ctx.lineTo(pts[y2][x2 + 1].x, pts[y2][x2 + 1].y);
        ctx.lineTo(pts[y2 + 1][x2].x, pts[y2 + 1][x2].y);
        ctx.stroke();
      }
    }
    ctx.globalAlpha = 1;
    requestAnimationFrame(draw);
  }
  draw();
}
